import React, { useState } from 'react';
import styled from 'styled-components';
import CidadeSearch from '../components/CidadeSearch';
import api from '../services/api';
import { Header } from '../components/Header';
import { Card } from '../components/Card';
import { Button } from '../components/Button';

const Container = styled.div`
  min-height: 100vh;
  background-color: ${props => props.theme.colors.background};
`;

const Content = styled.main`
  max-width: 1200px;
  margin: 0 auto;
  padding: ${props => props.theme.spacing.xl};
`;

const PageTitle = styled.h1`
  font-size: ${props => props.theme.fontSizes.xxlarge};
  color: ${props => props.theme.colors.primary};
  margin-bottom: ${props => props.theme.spacing.xl};
  font-weight: 700;
  border-left: 5px solid ${props => props.theme.colors.primary};
  padding-left: ${props => props.theme.spacing.md};
`;

const SearchSection = styled.div`
  background: ${props => props.theme.colors.white};
  border-radius: ${props => props.theme.borderRadius.large};
  padding: ${props => props.theme.spacing.xl};
  margin-bottom: ${props => props.theme.spacing.xl};
  box-shadow: ${props => props.theme.shadows.small};
`;

const SearchTitle = styled.h3`
  font-size: ${props => props.theme.fontSizes.large};
  color: ${props => props.theme.colors.primary};
  margin-bottom: ${props => props.theme.spacing.lg};
  font-weight: 600;
`;

const SearchRow = styled.div`
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: ${props => props.theme.spacing.lg};
  margin-bottom: ${props => props.theme.spacing.lg};
  
  @media (max-width: 768px) {
    grid-template-columns: 1fr;
  }
`;

const SearchButton = styled(Button)`
  margin-top: ${props => props.theme.spacing.md};
`;

const ViagensList = styled.div`
  display: flex;
  flex-direction: column;
  gap: ${props => props.theme.spacing.md};
`;

const ViagemCard = styled(Card)`
  padding: ${props => props.theme.spacing.lg};
  cursor: pointer;
  transition: all 0.3s ease;
  
  &:hover {
    transform: translateX(4px);
    box-shadow: ${props => props.theme.shadows.medium};
  }
`;

const ViagemHeader = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: ${props => props.theme.spacing.md};
  flex-wrap: wrap;
  gap: ${props => props.theme.spacing.sm};
`;

const CidadeInfo = styled.div`
  font-size: 18px;
  font-weight: 700;
  color: ${props => props.theme.colors.primary};
`;

const DataInfo = styled.div`
  color: ${props => props.theme.colors.darkGray};
  font-size: 14px;
`;

const DetalhesGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: ${props => props.theme.spacing.md};
  margin-top: ${props => props.theme.spacing.md};
  padding-top: ${props => props.theme.spacing.md};
  border-top: 1px solid ${props => props.theme.colors.gray};
`;

const DetalheItem = styled.div`
  display: flex;
  flex-direction: column;
`;

const DetalheLabel = styled.span`
  font-size: 12px;
  color: ${props => props.theme.colors.darkGray};
  margin-bottom: 4px;
`;

const DetalheValue = styled.span`
  font-size: 16px;
  font-weight: 500;
  color: ${props => props.theme.colors.black};
`;

const EmptyState = styled.div`
  text-align: center;
  padding: ${props => props.theme.spacing.xxl} ${props => props.theme.spacing.xl};
  color: ${props => props.theme.colors.darkGray};
`;

const formatDate = (date) => {
  if (!date) return 'Não definida';
  return new Date(date).toLocaleDateString('pt-BR');
};

const formatMoney = (value) => {
  if (value === null || value === undefined) return 'R$ 0,00';
  return new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL'
  }).format(value);
};

const PesquisarViagens = () => {
  const [cidadeOrigem, setCidadeOrigem] = useState(null);
  const [cidadeDestino, setCidadeDestino] = useState(null);
  const [viagens, setViagens] = useState([]);
  const [loading, setLoading] = useState(false);

  const handleSearch = async () => {
    if (!cidadeOrigem && !cidadeDestino) {
      alert('Selecione pelo menos uma cidade para pesquisar');
      return;
    }
    
    setLoading(true);
    try {
      const params = {};
      if (cidadeOrigem) params.id_saida = cidadeOrigem.id;
      if (cidadeDestino) params.id_chegada = cidadeDestino.id;
      
      const response = await api.get('/viagens', { params });
      setViagens(response.data);
    } catch (error) {
      console.error('Erro ao pesquisar viagens:', error);
      alert(error.response?.data?.error || 'Erro ao pesquisar viagens');
    } finally {
      setLoading(false);
    }
  };

  const handleClearFilters = () => {
    setCidadeOrigem(null);
    setCidadeDestino(null);
    setViagens([]);
  };

  return (
    <Container>
      <Header />
      
      <Content>
        <PageTitle>Pesquisar Viagens</PageTitle>
        
        <SearchSection>
          <SearchTitle>Filtrar por cidade</SearchTitle>
          <SearchRow>
            <div>
              <label style={{ display: 'block', marginBottom: '8px', fontWeight: 500 }}>
                Cidade de Origem
              </label>
              <CidadeSearch 
                onSelect={setCidadeOrigem}
                placeholder="Todas as origens"
              />
            </div>
            <div>
              <label style={{ display: 'block', marginBottom: '8px', fontWeight: 500 }}>
                Cidade de Destino
              </label>
              <CidadeSearch 
                onSelect={setCidadeDestino}
                placeholder="Todos os destinos"
              />
            </div>
          </SearchRow>
          
          <div style={{ display: 'flex', gap: '16px', marginTop: '20px' }}>
            <SearchButton onClick={handleSearch} disabled={loading}>
              {loading ? 'Pesquisando...' : '🔍 Pesquisar Viagens'}
            </SearchButton>
            {(cidadeOrigem || cidadeDestino) && (
              <Button outline onClick={handleClearFilters}>
                Limpar Filtros
              </Button>
            )}
          </div>
        </SearchSection>
        
        {viagens.length > 0 && (
          <>
            <h3 style={{ marginBottom: '20px' }}>
              Resultados: {viagens.length} viagem(ns) encontrada(s)
            </h3>
            <ViagensList>
              {viagens.map((viagem) => (
                <ViagemCard key={viagem.id_viagem}>
                  <ViagemHeader>
                    <CidadeInfo>
                      {viagem.cidade_saida || '?'} → {viagem.cidade_chegada || '?'}
                    </CidadeInfo>
                    <DataInfo>
                      {formatDate(viagem.data_entrada)} a {formatDate(viagem.data_chegada)}
                    </DataInfo>
                  </ViagemHeader>
                  
                  <DetalhesGrid>
                    <DetalheItem>
                      <DetalheLabel>KM percorrido</DetalheLabel>
                      <DetalheValue>
                        {viagem.km_entrada && viagem.km_saida 
                          ? `${viagem.km_entrada - viagem.km_saida} km` 
                          : 'Não informado'}
                      </DetalheValue>
                    </DetalheItem>
                    
                    <DetalheItem>
                      <DetalheLabel>Peso transportado</DetalheLabel>
                      <DetalheValue>
                        {viagem.peso_saida ? `${viagem.peso_saida} toneladas` : 'Não informado'}
                      </DetalheValue>
                    </DetalheItem>
                    
                    <DetalheItem>
                      <DetalheLabel>Valor do frete</DetalheLabel>
                      <DetalheValue>
                        {formatMoney(viagem.total_bruto)}
                      </DetalheValue>
                    </DetalheItem>
                    
                    <DetalheItem>
                      <DetalheLabel>Valor líquido</DetalheLabel>
                      <DetalheValue>
                        {formatMoney(viagem.total_liquido)}
                      </DetalheValue>
                    </DetalheItem>
                  </DetalhesGrid>
                </ViagemCard>
              ))}
            </ViagensList>
          </>
        )}
        
        {!loading && viagens.length === 0 && (cidadeOrigem || cidadeDestino) && (
          <EmptyState>
            <p>Nenhuma viagem encontrada para os filtros selecionados.</p>
            <Button small onClick={handleClearFilters} style={{ marginTop: '16px' }}>
              Limpar Filtros
            </Button>
          </EmptyState>
        )}
      </Content>
    </Container>
  );
};

export default PesquisarViagens;
